mapper.select:
SELECT st.id, st.name, st.description, st.icon, st.category, st.difficulty_level, st.status, st.sort_order, st.create_time, st.update_time, COUNT(sn.id) AS node_count FROM skill_tree st LEFT JOIN skill_node sn ON st.id = sn.tree_id AND sn.deleted = 0 WHERE st.deleted = 0 AND st.status = 1
AND st.category = #{category}
GROUP BY st.id ORDER BY st.sort_order ASC, st.create_time DESC
